const e=JSON.parse('{"key":"v-95b16e96","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/11-%E8%9C%A1%E7%83%9B%E5%9B%BE%E4%B8%8E%E4%BA%A4%E6%98%93%E9%87%8F%E6%8C%81%E4%BB%93%E9%87%8F.html","title":"蜡烛图与交易量持仓量","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["交易量","持仓量"],"order":11,"description":"蜡烛图与交易量持仓量 交易量的技术意义是，一段行情的交易量越重，则这段行情背后的市场力量越强大。只要交易量保持增长的态势，那么，当前的价格趋势就将持续下去。但是，如果在价格趋势发展时，交易量不增反降，那么，判断当前趋势仍将继续发展的理由就不充分了。另外，我们还可以通过交易量来验证市场的顶部或底部过程。当市场向下试探某一支撑水平时，如果交易量较轻，则意味着卖出压力减弱了，因此构成了一个看涨信号。反过来，当市场向上试探先前的高点时，如果交易量较轻，则证明买进力量减弱了，构成了一个看跌信号。 虽然我们可以利用交易量来作为一项有力的辅助手段，衡量价格运动背后的市场强度，但是，有一些不利的因素在一定的程度上给交易量的技术意义打了折扣，特别是在期货市场上，这个问题尤为突出。首先，在期货市场上，交易量的数据是延迟一天后公布的。其次，差价套利交易有可能扭曲交易量的数字一特别是扭曲个别合约月份的交易量。另外，随着许多期货市场的期权交易日益盛行，交易量数据也可能被相应的期权套利交易所扭曲。尽管存在上述各种不利因素，交易量分析依然是一种很有价值的研究工具。在这一章中，我们来探讨将交易量与蜡烛图技术相结合的一些办法。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/11-%E8%9C%A1%E7%83%9B%E5%9B%BE%E4%B8%8E%E4%BA%A4%E6%98%93%E9%87%8F%E6%8C%81%E4%BB%93%E9%87%8F.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"蜡烛图与交易量持仓量"}],["meta",{"property":"og:description","content":"蜡烛图与交易量持仓量 交易量的技术意义是，一段行情的交易量越重，则这段行情背后的市场力量越强大。只要交易量保持增长的态势，那么，当前的价格趋势就将持续下去。但是，如果在价格趋势发展时，交易量不增反降，那么，判断当前趋势仍将继续发展的理由就不充分了。另外，我们还可以通过交易量来验证市场的顶部或底部过程。当市场向下试探某一支撑水平时，如果交易量较轻，则意味着卖出压力减弱了，因此构成了一个看涨信号。反过来，当市场向上试探先前的高点时，如果交易量较轻，则证明买进力量减弱了，构成了一个看跌信号。 虽然我们可以利用交易量来作为一项有力的辅助手段，衡量价格运动背后的市场强度，但是，有一些不利的因素在一定的程度上给交易量的技术意义打了折扣，特别是在期货市场上，这个问题尤为突出。首先，在期货市场上，交易量的数据是延迟一天后公布的。其次，差价套利交易有可能扭曲交易量的数字一特别是扭曲个别合约月份的交易量。另外，随着许多期货市场的期权交易日益盛行，交易量数据也可能被相应的期权套利交易所扭曲。尽管存在上述各种不利因素，交易量分析依然是一种很有价值的研究工具。在这一章中，我们来探讨将交易量与蜡烛图技术相结合的一些办法。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-01-27T15:35:20.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"交易量"}],["meta",{"property":"article:tag","content":"持仓量"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-01-27T15:35:20.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"蜡烛图与交易量持仓量\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-01-27T15:35:20.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"交易量与蜡烛图","slug":"交易量与蜡烛图","link":"#交易量与蜡烛图","children":[]},{"level":2,"title":"权衡交易量（OBV）","slug":"权衡交易量-obv","link":"#权衡交易量-obv","children":[]},{"level":2,"title":"OBV与蜡烛图","slug":"obv与蜡烛图","link":"#obv与蜡烛图","children":[]},{"level":2,"title":"即时交易量（TM）","slug":"即时交易量-tm","link":"#即时交易量-tm","children":[]},{"level":2,"title":"即时交易量（TM）与蜡烛图","slug":"即时交易量-tm-与蜡烛图","link":"#即时交易量-tm-与蜡烛图","children":[]},{"level":2,"title":"持仓量","slug":"持仓量","link":"#持仓量","children":[]},{"level":2,"title":"持仓量与蜡烛图","slug":"持仓量与蜡烛图","link":"#持仓量与蜡烛图","children":[]}],"git":{"createdTime":1706369720000,"updatedTime":1706369720000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":19.19,"words":5758},"filePathRelative":"证券交易/日本蜡烛图技术/11-蜡烛图与交易量持仓量.md","localizedDate":"2024年1月17日","excerpt":"<h1> 蜡烛图与交易量持仓量</h1>\\n<p>交易量的技术意义是，一段行情的交易量越重，则这段行情背后的市场力量越强大。只要交易量保持增长的态势，那么，当前的价格趋势就将持续下去。但是，如果在价格趋势发展时，交易量不增反降，那么，判断当前趋势仍将继续发展的理由就不充分了。另外，我们还可以通过交易量来验证市场的顶部或底部过程。当市场向下试探某一支撑水平时，如果交易量较轻，则意味着卖出压力减弱了，因此构成了一个看涨信号。反过来，当市场向上试探先前的高点时，如果交易量较轻，则证明买进力量减弱了，构成了一个看跌信号。</p>\\n<p>虽然我们可以利用交易量来作为一项有力的辅助手段，衡量价格运动背后的市场强度，但是，有一些不利的因素在一定的程度上给交易量的技术意义打了折扣，特别是在期货市场上，这个问题尤为突出。首先，在期货市场上，交易量的数据是延迟一天后公布的。其次，差价套利交易有可能扭曲交易量的数字一特别是扭曲个别合约月份的交易量。另外，随着许多期货市场的期权交易日益盛行，交易量数据也可能被相应的期权套利交易所扭曲。尽管存在上述各种不利因素，交易量分析依然是一种很有价值的研究工具。在这一章中，我们来探讨将交易量与蜡烛图技术相结合的一些办法。</p>","autoDesc":true}');export{e as data};
